#!/usr/bin/env python3
import gzip,base64,os,subprocess

# Write PhotoWing HTML
html=gzip.decompress(base64.b64decode(""))
os.makedirs("/opt/photowing",exist_ok=True)
with open("/opt/photowing/index.html","wb") as f: f.write(html)
print(f"HTML written: {len(html):,} bytes")

# Nginx config for /photowing/
nginx_conf = """location /photowing/ {
    alias /opt/photowing/;
    index index.html;
    try_files $uri $uri/ /photowing/index.html;
    
    # Security headers
    add_header X-Frame-Options "SAMEORIGIN" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header Permissions-Policy "camera=(self),microphone=(self)" always;
    
    # Camera needs HTTPS (already set)
    expires -1;
}
"""
conf_path="/etc/nginx/conf.d/photowing.conf"
if not os.path.exists(conf_path):
    with open(conf_path,"w") as f: f.write(nginx_conf)
    print("Nginx config created")
else:
    print("Nginx config already exists, skipping")

# Test nginx
r=subprocess.run(["nginx","-t"],capture_output=True,text=True)
if r.returncode==0:
    subprocess.run(["systemctl","reload","nginx"])
    print("Nginx reloaded OK")
else:
    print("Nginx test failed:",r.stderr[:200])

# Verify
import urllib.request
try:
    resp=urllib.request.urlopen("http://127.0.0.1/photowing/")
    print(f"UP: HTTP {resp.status} - {len(resp.read()):,} bytes")
except Exception as e:
    print(f"DOWN: {e}")
